-- 2. OTROS TIPOS MENSUALES (ID: 3, 4, 5) 
-- (Integral, Aprendizaje, Cátedra)
-- ==========================================
-- Usamos un bloque anónimo para no escribir 36 líneas más
BEGIN
  FOR m IN 2..12 LOOP
    FOR t IN 3..5 LOOP
      VALUES (t, '2025-'||LPAD(m,2,'0'), TO_DATE('2025-'||m||'-01','YYYY-MM-DD'), LAST_DAY(TO_DATE('2025-'||m||'-01','YYYY-MM-DD')), 'CERRADO');
    END LOOP;
  END LOOP;
  
  -- Enero 2026 para los 3 tipos
  FOR t IN 3..5 LOOP
      VALUES (t, '2026-01', TO_DATE('2026-01-01','YYYY-MM-DD'), TO_DATE('2026-01-31','YYYY-MM-DD'), 'CERRADO');
  END LOOP;
END;
