-- Detalle de Devengos y Deducciones por Volante
-- Conceptos: 1 (Salario), 2 (Extras), 3 (Salud), 4 (Pensión)



SET SERVEROUTPUT ON;

DECLARE
    /* AUTOR: SANTIAGO PINZÓN VÁSQUEZ
       FECHA: 02/03/2026
       DESCRIPCIÓN: Cursor corregido para obtener ID del departamento 80
    */

    CURSOR cursor_empleados IS 
        SELECT DEPARTMENT_ID
        FROM EMPLOYEES
        WHERE DEPARTMENT_ID = 80;

    
    v_id_dep NUMBER(4); 

BEGIN
    OPEN cursor_empleados;

    
    FETCH cursor_empleados INTO v_id_dep;

    IF cursor_empleados%FOUND THEN
        dbms_output.put_line('Departamento encontrado: ' || v_id_dep);
    ELSE
        dbms_output.put_line('No se encontraron empleados en el departamento 80');
    END IF;

    CLOSE cursor_empleados;
END;
/
DECLARE
    /* AUTOR: SANTIAGO PINZÓN VÁSQUEZ
       DESCRIPCIÓN: Cursor dinámico que pide el ID por consola (&)
       FECHA: 02/03/2026
    */

    v_target_dept NUMBER := &DIGITE_ID_DEPARTAMENTO;

    CURSOR c_empleados IS
      SELECT employee_id, first_name, last_name, department_id
      FROM EMPLOYEES
      WHERE department_id = v_target_dept;

    v_emp c_empleados%ROWTYPE;
    v_contador NUMBER := 0;
BEGIN
    dbms_output.put_line('--- LISTADO PARA EL DEPARTAMENTO: ' || v_target_dept || ' ---');

    OPEN c_empleados;
    LOOP
        FETCH c_empleados INTO v_emp;
        EXIT WHEN c_empleados%NOTFOUND;
        
        v_contador := v_contador + 1;
        dbms_output.put_line(
            v_emp.employee_id || ' - ' ||
            v_emp.first_name || ' ' ||
            v_emp.last_name ||
            ' (Depto: ' || v_emp.department_id || ')'
        );
    END LOOP;
    
    
    IF v_contador = 0 THEN
        dbms_output.put_line('No se encontró a nadie en el ID: ' || v_target_dept);
    ELSE
        dbms_output.put_line('Total de empleados: ' || v_contador);
    END IF;

    CLOSE c_empleados;
END;
/
DECLARE
    /* AUTOR: SANTIAGO PINZÓN VÁSQUEZ
    FECHA: 02/03/2026
    DESCRIPCIÓN: Reporte de nómina mensual usando cursores y variables de sustitución
    */
    
    -- Capturamos mes y año con el "scanner" (&)
    v_mes  VARCHAR2(2) := '&MM_EJ_02';
    v_anio VARCHAR2(4) := '&YYYY_EJ_2026';
    
    -- Cursor que une los volantes con los datos del empleado
    CURSOR c_nomina IS
        SELECT 
            p.employee_id,
            e.first_name || ' ' || e.last_name as nombre_completo,
            p.gross_total,
            p.ded_total,
            p.net_total,
            p.status
        FROM pay_payslips p
        JOIN employees e ON p.employee_id = e.employee_id
        WHERE TO_CHAR(p.calc_date, 'MM') = v_mes
          AND TO_CHAR(p.calc_date, 'YYYY') = v_anio;


    v_total_nomina NUMBER := 0;
    v_conteo_emp   NUMBER := 0;

BEGIN
    dbms_output.put_line('================================================================');
    dbms_output.put_line('REPORTE DE NÓMINA: ' || v_mes || '/' || v_anio);
    dbms_output.put_line('================================================================');
    dbms_output.put_line('ID EMP  | NOMBRE               | BRUTO      | DEDUC.    | NETO');
    dbms_output.put_line('----------------------------------------------------------------');

    -- Recorremos con un FOR para que sea más eficiente
    FOR r_nom IN c_nomina LOOP
        v_conteo_emp := v_conteo_emp + 1;
        v_total_nomina := v_total_nomina + r_nom.net_total;
        
        dbms_output.put_line(
            RPAD(r_nom.employee_id, 8) || ' | ' ||
            RPAD(SUBSTR(r_nom.nombre_completo, 1, 20), 20) || ' | ' ||
            LPAD(TO_CHAR(r_nom.gross_total, '999,999,999'), 10) || ' | ' ||
            LPAD(TO_CHAR(r_nom.ded_total, '999,999,999'), 9) || ' | ' ||
            LPAD(TO_CHAR(r_nom.net_total, '999,999,999'), 10)
        );
    END LOOP;

    dbms_output.put_line('----------------------------------------------------------------');
    
    
    IF v_conteo_emp = 0 THEN
        dbms_output.put_line('AVISO: No se encontraron registros para ese periodo.');
    ELSE
        dbms_output.put_line('Resumen:');
        dbms_output.put_line('Total Empleados Pagados: ' || v_conteo_emp);
        dbms_output.put_line('Costo Total Nómina (Neto): $' || TO_CHAR(v_total_nomina, '999,999,999,999'));
    END IF;
    
    dbms_output.put_line('================================================================');
END;
/